function igmShowRules() { igmShowSub('rules'); }

// ── IN-GAME INVITE FRIENDS ─────────────────────────────
let _igmFriendsList = [];
function igmInviteFriend() {
  const statusEl = document.getElementById('igm-invite-status');
  if (statusEl) statusEl.textContent = '';
  const input = document.getElementById('igm-invite-username');
  if (input) input.value = '';
  // Pre-fetch friends list
  _fetchIgmFriends();
  igmShowSub('invite');
}
async function _fetchIgmFriends() {
  try {
    const token = igmToken || (() => { try { return JSON.parse(sessionStorage.getItem('sipsam_user')||'{}').token||null; } catch(e){ return null; }})();
    if (!token) return;
    const res = await fetch('/api/game/friends', { headers:{ 'Authorization':'Bearer '+token }, credentials:'include' });
    if (res.ok) { const d = await res.json(); _igmFriendsList = d.friends || []; }
  } catch(e) { console.warn('Failed to fetch friends for igm:', e); }
}
function onIgmInviteInput(val) {
  const dd = document.getElementById('igm-invite-dropdown');
  if (!dd) return;
  if (!val.trim()) { _showIgmFriendsList(dd); return; }
  const q = val.toLowerCase();
  const matches = _igmFriendsList.filter(f => f.username.toLowerCase().includes(q));
  dd.innerHTML = matches.map(f => `<div style="padding:8px 12px;cursor:pointer;color:#f0f6ff;font-size:13px;border-bottom:1px solid #1a2d50" onclick="selectIgmInvitee('${f.username}')">${f.username}</div>`).join('');
  dd.style.display = matches.length ? 'block' : 'none';
}
function onIgmInviteFocus() {
  const dd = document.getElementById('igm-invite-dropdown');
  if (dd) _showIgmFriendsList(dd);
}
function _showIgmFriendsList(dd) {
  dd.innerHTML = _igmFriendsList.map(f => `<div style="padding:8px 12px;cursor:pointer;color:#f0f6ff;font-size:13px;border-bottom:1px solid #1a2d50" onclick="selectIgmInvitee('${f.username}')">${f.username}</div>`).join('');
  dd.style.display = _igmFriendsList.length ? 'block' : 'none';
}
function selectIgmInvitee(name) {
  const input = document.getElementById('igm-invite-username');
  if (input) input.value = name;
  const dd = document.getElementById('igm-invite-dropdown');
  if (dd) dd.style.display = 'none';
}
async function sendIgmInvite() {
  const input    = document.getElementById('igm-invite-username');
  const statusEl = document.getElementById('igm-invite-status');
  if (!input || !statusEl) return;
  const username = input.value.trim();
  if (!username) { statusEl.textContent = '⚠️ Enter a username.'; statusEl.style.color = '#fca5a5'; return; }
  statusEl.textContent = 'Sending invite...'; statusEl.style.color = '#7a9ac0';
  try {
    const token = igmToken || (() => { try { return JSON.parse(sessionStorage.getItem('sipsam_user')||'{}').token||null; } catch(e){ return null; }})();
    if (!token) { statusEl.textContent = '⚠️ Not authenticated.'; statusEl.style.color = '#fca5a5'; return; }
    const tableConfig = igmTableCfg || {};
    const res = await fetch('/api/friends/invite', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token },
      credentials: 'include',
      body: JSON.stringify({
        toUsername: username, game: 'sipsam', roomId: myRoomId,
        tableMinBet: tableConfig.minBet || selectedMinBet,
        tableConfig: {
          minBet: tableConfig.minBet || selectedMinBet, maxBet: tableConfig.maxBet,
          walletSize: tableConfig.walletSize || tableConfig.wallet,
          wallet: tableConfig.walletSize || tableConfig.wallet,
          inc: tableConfig.increment || tableConfig.inc,
          minBank: tableConfig.minBank || tableConfig.bankRequired,
          rounds: window._gameOverState?.maxRounds || selectedRounds || 10,
          blitz: false, roomId: myRoomId
        }
      })
    });
    const data = await res.json();
    if (data.ok) {
      statusEl.textContent = `✅ Invite sent to ${username}!`; statusEl.style.color = '#22c55e';
      input.value = '';
      setTimeout(() => { if (statusEl) statusEl.textContent = ''; }, 4000);
    } else {
      statusEl.textContent = '❌ ' + (data.error || 'Failed to send.'); statusEl.style.color = '#fca5a5';
    }
  } catch(e) {
    statusEl.textContent = '⚠️ Server error.'; statusEl.style.color = '#fca5a5';
  }
}

function igmExit() {

function igmShowRules() { igmShowSub('rules'); }

// ── PAYOUTS & SPECIALS — focused payout reference ─────────────
// Mirrors poker-server/logic.js: SPECIAL_BONUS (non-VIP) and SPECIAL_BONUS_VIP.
// VIP tier = tableMinBet >= 10000 (matches PokerRoom.js: this.gameState.isVip = cfg.minBet >= 10000)
const SIPSAM_SPECIALS = [
  { name:'No Face',                     mult:2,  bonus:1000,    bonusVip:100000 },
  { name:'Four of a Kind',              mult:3,  bonus:2500,    bonusVip:250000 },
  { name:'Straight Flush',              mult:3,  bonus:2500,    bonusVip:250000 },
  { name:'Straight-Straight-Straight',  mult:5,  bonus:7000,    bonusVip:500000 },
  { name:'Flush-Flush-Flush',           mult:5,  bonus:7000,    bonusVip:500000 },
  { name:'Royal Flush',                 mult:7,  bonus:10000,   bonusVip:750000 },
  { name:'6½ Pairs',                    mult:8,  bonus:15000,   bonusVip:1000000 },
  { name:'Full Suit',                   mult:10, bonus:50000,   bonusVip:3000000 },
];

function igmShowPayouts() {
  const minBet = (igmTableCfg?.minBet) || (window._lastState?.tableMinBet) || 0;
  const isVip  = minBet >= 10000;

  // Tier badge
  const tier = document.getElementById('igm-payouts-tier');
  if (tier) {
    if (isVip) {
      tier.style.background = 'linear-gradient(135deg, rgba(201,168,76,.15), rgba(232,201,106,.05))';
      tier.style.border = '1px solid #c9a84c';
      tier.style.color = '#e8c96a';
      tier.textContent = '💎 VIP TABLE — High-tier bonuses active (min bet $' + minBet.toLocaleString() + ')';
    } else {
      tier.style.background = 'rgba(26,140,255,.08)';
      tier.style.border = '1px solid #1a2d50';
      tier.style.color = '#7a9ac0';
      tier.textContent = 'Standard table (min bet $' + minBet.toLocaleString() + ')';
    }
  }

  // Bonus column header reflects tier
  const bonusCol = document.getElementById('igm-payouts-bonus-col');
  if (bonusCol) bonusCol.textContent = isVip ? 'BONUS (VIP)' : 'BONUS';

  // Render table body
  const tbody = document.getElementById('igm-payouts-tbody');
  if (tbody) {
    const rows = SIPSAM_SPECIALS.map((s, i) => {
      const bonus = isVip ? s.bonusVip : s.bonus;
      const last  = i === SIPSAM_SPECIALS.length - 1;
      const border = last ? '' : 'border-bottom:1px solid rgba(255,255,255,.05);';
      return `<tr style="${border}">
        <td style="padding:5px 6px;color:#e8c96a">${s.name}</td>
        <td style="text-align:center;padding:5px 6px;color:#22c55e;font-weight:700">${s.mult}×</td>
        <td style="text-align:right;padding:5px 6px;color:#4aabff;font-weight:700">+$${bonus.toLocaleString()}</td>
      </tr>`;
    }).join('');
    tbody.innerHTML = rows;
  }

  igmShowSub('payouts');
}
